# layer1_tool_guard.py — rejects hallucinated or malformed tool calls
import json
from typing import Any
import jsonschema

TOOL_REGISTRY: dict[str, dict] = {
    "search_web": {
        "type": "object",
        "properties": {
            "query": {"type": "string"},
            "max_results": {"type": "integer", "default": 5},
        },
        "required": ["query"],
    },
    "read_file": {
        "type": "object",
        "properties": {"path": {"type": "string"}},
        "required": ["path"],
    },
    "write_file": {
        "type": "object",
        "properties": {
            "path": {"type": "string"},
            "content": {"type": "string"},
        },
        "required": ["path", "content"],
    },
}


class ToolGuard:
    def __init__(self, registry: dict[str, dict]) -> None:
        self.registry = registry

    def validate(self, name: str, arguments: dict) -> None:
        """Raise ValueError if the call looks hallucinated."""
        if name not in self.registry:
            raise ValueError(
                f"Unknown tool '{name}'. Registered: {sorted(self.registry)}"
            )
        try:
            jsonschema.validate(instance=arguments, schema=self.registry[name])
        except jsonschema.ValidationError as exc:
            raise ValueError(f"Bad args for '{name}': {exc.message}") from exc

    def safe_run(self, name: str, arguments: dict, executors: dict[str, Any]) -> Any:
        self.validate(name, arguments)
        return executors[name](**arguments)


# --- demo ---
guard = ToolGuard(TOOL_REGISTRY)

try:
    guard.validate("query_customer_db", {"id": 42})  # hallucinated tool
except ValueError as e:
    print(f"BLOCKED: {e}")

try:
    guard.validate("search_web", {"query": 12345})  # wrong type
except ValueError as e:
    print(f"BLOCKED: {e}")

guard.validate("search_web", {"query": "hallucination benchmarks 2024"})
print("PASSED: search_web with valid args")
